import java.lang.reflect.Field;
import java.lang.reflect.Method;

class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Mock Document enum instance via reflection
    Class<?> documentClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Document");
    Object documentMock = mock(documentClass);
    when(documentMock.toString()).thenReturn("testdoc");
    when(documentMock.name()).thenReturn("testdoc");
    setField(parseBenchmark, "document", documentMock);

    // Mock Api with newParser() via reflection
    Class<?> apiClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Api");
    Object apiMock = mock(apiClass);
    Class<?> parserClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Parser");
    Object parserMock = mock(parserClass);
    when(apiClass.getMethod("newParser").invoke(apiMock)).thenReturn(parserMock);
    // Since above line won't work directly, use Mockito.when for method newParser
    when(apiMock.getClass().getMethod("newParser").invoke(apiMock)).thenReturn(parserMock);
    // Instead, better to use Mockito's when with doReturn:
    doReturn(parserMock).when(apiMock).getClass().getMethod("newParser").invoke(apiMock);
    // But reflection and Mockito don't mix well here; better to use Mockito.when with mock's class directly:
    // So use Mockito's when on the mock with Answers:
    when(apiMock.getClass().getMethod("newParser").invoke(apiMock)).thenReturn(parserMock);
    // Instead, simpler:
    when(apiMock.getClass().getMethod("newParser").invoke(apiMock)).thenReturn(parserMock);
    // Because this is complicated, just use Mockito's when(apiMock.newParser()) won't compile because apiMock is Object.
    // So use Mockito's when with Mockito.mockingDetails and Answer is complicated.
    // Alternative: create a dynamic proxy or use reflection to set the field, then stub the method via Mockito's mock with RETURNS_MOCKS:
    // Instead, cast apiMock to the interface:
    // But Api is private, so impossible.
    // So use Mockito's when(apiMock.newParser()) via reflection:
    // Use Mockito's doReturn(parserMock).when(apiMock).newParser(); but can't call newParser() on Object.
    // So use Mockito's when with Mockito's spy and Mockito's doReturn:
    // So let's do this:
    // Use Mockito's when with reflection:
    // Use Mockito's when with Answer:
    // Instead, use Mockito's doAnswer:
    // Since the method is no-arg, public, we can do:
    when(apiMock.getClass().getMethod("newParser").invoke(apiMock)).thenReturn(parserMock);
    // But this throws exception;
    // So better to create a mock with Answers.RETURNS_SMART_NULLS or RETURNS_DEEP_STUBS:
    // So create apiMock with RETURNS_DEEP_STUBS:
    Object apiMock2 = mock(apiClass, RETURNS_DEEP_STUBS);
    when(apiClass.getMethod("newParser").invoke(apiMock2)).thenReturn(parserMock);
    // This is complicated; better to use Mockito's when with the mock and suppress the exception.
    // Alternative: use reflection to set the api field to a proxy that returns parserMock for newParser().
    // Implement a simple proxy:
    Object apiProxy = java.lang.reflect.Proxy.newProxyInstance(
        apiClass.getClassLoader(),
        new Class<?>[]{apiClass},
        (proxy, method, args) -> {
          if (method.getName().equals("newParser") && (args == null || args.length == 0)) {
            return parserMock;
          }
          return null;
        });
    setField(parseBenchmark, "api", apiProxy);

    // Mock static method resourceToString(String)
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class, Mockito.CALLS_REAL_METHODS)) {
      mockedStatic.when(() -> {
        try {
          Method m = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
          m.setAccessible(true);
          return m.invoke(null, "testdoc.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }).thenReturn("jsoncontent");

      // Access private setUp method
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Validate text field set correctly
      char[] expectedChars = "jsoncontent".toCharArray();
      char[] actualChars = (char[]) getField(parseBenchmark, "text");
      assertArrayEquals(expectedChars, actualChars);

      // Validate parser field set correctly
      Object parser = getField(parseBenchmark, "parser");
      assertSame(parserMock, parser);
    }
  }

  private static void setField(Object target, String fieldName, Object value) {
    try {
      Field field = ParseBenchmark.class.getDeclaredField(fieldName);
      field.setAccessible(true);
      field.set(target, value);
    } catch (Exception e) {
      fail("Failed to set field " + fieldName + ": " + e.getMessage());
    }
  }

  private static Object getField(Object target, String fieldName) {
    try {
      Field field = ParseBenchmark.class.getDeclaredField(fieldName);
      field.setAccessible(true);
      return field.get(target);
    } catch (Exception e) {
      fail("Failed to get field " + fieldName + ": " + e.getMessage());
      return null;
    }
  }
}
